import { createForks, teardownForks } from '@tigrisdata/agent-kit';
import { S3Client, PutObjectCommand, ListObjectsV2Command } from '@aws-sdk/client-s3';
import * as fs from 'fs/promises';

async function main() {
  // 1. Read trial ID
  const trialIdRaw = (await fs.readFile('/logs/artifacts/trial_id', 'utf-8')).trim();
  const trialId = trialIdRaw.toLowerCase().replace(/[^a-z0-9.-]/g, '-');

  const sourceBucketName = `harbor-isolation-${trialId}`;
  const forkPrefix = `audit-fork-${trialId}`;

  // 2. Create forks
  const { data: forkSet, error } = await createForks(sourceBucketName, 3, {
    prefix: forkPrefix,
    credentials: { role: 'Editor' }
  });

  if (error) {
    throw new Error(`Failed to create forks: ${error.message}`);
  }

  if (!forkSet || forkSet.forks.length !== 3) {
    throw new Error('Expected exactly 3 forks to be created');
  }

  try {
    // 3. Upload files to forks concurrently
    const uploadPromises = forkSet.forks.map((fork, index) => {
      const client = new S3Client({
        region: 'REDACTED',
        endpoint: 'REDACTED',
        credentials: {
          accessKeyId: fork.credentials!.accessKeyId,
          secretAccessKey: fork.credentials!.secretAccessKey,
        }
      });
      const key = `agent-${index + 1}.out`;
      return client.send(new PutObjectCommand({
        Bucket: fork.bucket,
        Key: key,
        Body: `Content for ${key}`
      })).then(() => ({ client, fork, index, key }));
    });

    const uploadResults = await Promise.all(uploadPromises);

    // 4. Audit bucket state
